// Saved registers for kernel context switches.
struct context {
  uint64 ra;
  uint64 sp;

  // callee-saved
  uint64 s0;
  uint64 s1;
  uint64 s2;
  uint64 s3;
  uint64 s4;
  uint64 s5;
  uint64 s6;
  uint64 s7;
  uint64 s8;
  uint64 s9;
  uint64 s10;
  uint64 s11;
};

// Per-CPU state.
struct cpu {
  struct proc *proc;          // The process running on this cpu, or null.
  struct context context;     // swtch() here to enter scheduler().
  int noff;                   // Depth of push_off() nesting.
  int intena;                 // Were interrupts enabled before push_off()?
};

extern struct cpu cpus[NCPU];

enum procstate { UNUSED, SLEEPING, RUNNABLE, RUNNING, ZOMBIE };

struct proc_timeval {
  long tv_sec;
  long tv_usec;
};

struct proc_itimerval {
  struct proc_timeval it_interval;
  struct proc_timeval it_value;
};

struct proc_sigaction {
  uint64 handler;
  uint64 flags;
  uint64 mask;
  uint64 restorer;
};

#define PROC_NGROUPS 16
#define PROC_MMAP_AREAS 32

struct proc_mmap_area {
  uint8 used;
  uint64 start;
  uint64 end;
  int prot;
  int flags;
};

// Per-process state
struct proc {
  struct spinlock lock;

  // p->lock must be held when using these:
  enum procstate state;        // Process state
  struct proc *parent;         // Parent process
  void *chan;                  // If non-zero, sleeping on chan
  int killed;                  // If non-zero, have been killed
  int termsig;                 // Linux wait status for signal termination
  int xstate;                  // Exit status to be returned to parent's wait
  int pid;                     // Process ID

  // ADD THESE FOUR LINES FOR TIME KEEPING
  uint64 utime;                // User time in ticks
  uint64 stime;                // System (kernel) time in ticks
  uint64 cutime;               // Children's user time
  uint64 cstime;               // Children's system time

  // these are private to the process, so p->lock need not be held.
  uint64 kstack;               // Virtual address of kernel stack
  uint64 sz;                   // Size of process memory (bytes)
  uint64 brk;                  // Linux program break; sz is mapped high-water
  uint64 clear_child_tid;      // Linux CLONE_CHILD_CLEARTID futex address
  uint64 sigmask;              // blocked signal mask for rt_sigprocmask
  struct proc_itimerval itimers[3]; // ITIMER_REAL/VIRTUAL/PROF state
  uint64 itimer_deadline[3];   // absolute r_time() deadlines for active timers
  uint64 sigpending;           // pending Linux signal bits, 1ULL << (signo - 1)
  struct proc_sigaction sigactions[65]; // 1..64 signal dispositions
  int sigactive;               // currently running a user signal handler
  uint64 sigsavedmask;         // mask restored by rt_sigreturn
  struct trapframe sigtf;      // interrupted context restored by rt_sigreturn
  struct proc_mmap_area mmap_areas[PROC_MMAP_AREAS];
  int nofile_limit;            // RLIMIT_NOFILE soft/hard value used by tests
  uint64 stack_limit;           // RLIMIT_STACK value visible to libc
  uint32 uid;
  uint32 euid;
  uint32 suid;
  uint32 gid;
  uint32 egid;
  uint32 sgid;
  int ngroups;
  uint32 groups[PROC_NGROUPS];
  uint32 umask;
  int is_thread;               // CLONE_VM child; shares user physical pages
  struct proc *vm_leader;       // shared address-space owner for CLONE_VM
  pagetable_t pagetable;       // User page table
  pagetable_t kpagetable;      // Kernel page table
  struct trapframe *trapframe; // data page for trampoline.S
  struct context context;      // swtch() here to run process
  struct file *ofile[NOFILE];  // Open files
  uint8 ofile_cloexec[NOFILE]; // Per-fd close-on-exec flags
  struct dirent *cwd;          // Current directory
  char cwd_path[MAXPATH];      // EXT4 current directory path
  char name[16];               // Process name (debugging)
  int tmask;                    // trace mask
};

