static int
proc_vm_has_other_users(struct proc *p)
{
  struct proc *leader = p->vm_leader ? p->vm_leader : p;

  for(struct proc *q = proc; q < &proc[NPROC]; q++) {
    if(q != p && q->state != UNUSED &&
       (q->vm_leader ? q->vm_leader : q) == leader)
      return 1;
  }
  return 0;
}

