// Must be called with interrupts disabled,
// to prevent race with process being moved
// to a different CPU.
int
cpuid()
{
  int id = r_tp();
  return id;
}

// Return this CPU's cpu struct.
// Interrupts must be disabled.
struct cpu*
mycpu(void) {
  int id = cpuid();
  struct cpu *c = &cpus[id];

  return c;
}

// Return the current struct proc *, or zero if none.
struct proc*
myproc(void) {
  push_off();
  struct cpu *c = mycpu();
  struct proc *p = c->proc;
  pop_off();
  return p;
}

int
allocpid() {
  int pid;

  acquire(&pid_lock);
  pid = nextpid;
  nextpid = nextpid + 1;
  release(&pid_lock);

  return pid;
}

// Look in the process table for an UNUSED proc.
// If found, initialize state required to run in the kernel,
// and return with p->lock held.
// If there are no free procs, or a memory allocation fails, return 0.
struct proc*
allocproc(void)
{
  struct proc *p;

  for(p = proc; p < &proc[NPROC]; p++) {
    acquire(&p->lock);
    if(p->state == ZOMBIE && p->is_thread)
      freeproc(p);
    release(&p->lock);
  }

  for(p = proc; p < &proc[NPROC]; p++) {
    acquire(&p->lock);
    if(p->state == UNUSED) {
      goto found;
    } else {
      release(&p->lock);
    }
  }
  return NULL;

found:
  p->pid = allocpid();
  // 添加times修改 ADD THESE LINES to initialize the time fields
  p->utime = 0;
  p->stime = 0;
  p->cutime = 0;
  p->cstime = 0;
  p->brk = 0;
  p->clear_child_tid = 0;
  p->termsig = 0;
  p->sigmask = 0;
  memset(p->itimers, 0, sizeof(p->itimers));
  memset(p->itimer_deadline, 0, sizeof(p->itimer_deadline));
  p->sigpending = 0;
  memset(p->sigactions, 0, sizeof(p->sigactions));
  p->sigactive = 0;
  p->sigsavedmask = 0;
  memset(&p->sigtf, 0, sizeof(p->sigtf));
  memset(p->mmap_areas, 0, sizeof(p->mmap_areas));
  p->nofile_limit = NOFILE;
  p->stack_limit = 256 * 1024;
  p->uid = 0;
  p->euid = 0;
  p->suid = 0;
  p->gid = 0;
  p->egid = 0;
  p->sgid = 0;
  p->ngroups = 1;
  p->groups[0] = 0;
  for (int i = 1; i < PROC_NGROUPS; i++)
    p->groups[i] = 0;
  p->umask = 022;
  p->is_thread = 0;
  p->vm_leader = p;
  p->cwd = 0;
  p->tmask = 0;
  for(int i = 0; i < NOFILE; i++)
    p->ofile[i] = 0;
  memset(p->ofile_cloexec, 0, sizeof(p->ofile_cloexec));
  // Allocate a trapframe page.
  if((p->trapframe = (struct trapframe *)kalloc()) == NULL){
    release(&p->lock);
    return NULL;
  }

  // An empty user page table.
  // And an identical kernel page table for this proc.
  if ((p->pagetable = proc_pagetable(p)) == NULL ||
      (p->kpagetable = proc_kpagetable()) == NULL) {
    freeproc(p);
    release(&p->lock);
    return NULL;
  }

  p->kstack = VKSTACK;
  p->cwd_path[0] = '/';
  p->cwd_path[1] = '\0';

  // Set up new context to start executing at forkret,
  // which returns to user space.
  memset(&p->context, 0, sizeof(p->context));
  p->context.ra = (uint64)forkret;
  p->context.sp = p->kstack + KSTACK_PAGES * PGSIZE;

  return p;
}

// free a proc structure and the data hanging from it,
// including user pages.
// p->lock must be held.
void
freeproc(struct proc *p)
{
  if(p->trapframe)
    kfree((void*)p->trapframe);
  p->trapframe = 0;
  if (p->kpagetable) {
    kvmfree(p->kpagetable, 1);
  }
  p->kpagetable = 0;
  if(p->pagetable) {
    if(p->is_thread || proc_vm_has_other_users(p))
      proc_freepagetable_nophys(p->pagetable, p->sz);
    else
      proc_freepagetable(p->pagetable, p->sz);
  }
  p->pagetable = 0;
  p->sz = 0;
  p->brk = 0;
  p->clear_child_tid = 0;
  p->sigmask = 0;
  memset(p->itimers, 0, sizeof(p->itimers));
  memset(p->itimer_deadline, 0, sizeof(p->itimer_deadline));
  p->sigpending = 0;
  memset(p->sigactions, 0, sizeof(p->sigactions));
  p->sigactive = 0;
  p->sigsavedmask = 0;
  memset(&p->sigtf, 0, sizeof(p->sigtf));
  memset(p->mmap_areas, 0, sizeof(p->mmap_areas));
  p->nofile_limit = NOFILE;
  p->stack_limit = 256 * 1024;
  p->uid = 0;
  p->euid = 0;
  p->suid = 0;
  p->gid = 0;
  p->egid = 0;
  p->sgid = 0;
  p->ngroups = 0;
  memset(p->groups, 0, sizeof(p->groups));
  p->umask = 022;
  p->is_thread = 0;
  p->vm_leader = 0;
  p->pid = 0;
  p->parent = 0;
  p->name[0] = 0;
  p->chan = 0;
  p->killed = 0;
  p->termsig = 0;
  p->xstate = 0;
  p->cwd = 0;
  p->tmask = 0;
  for(int i = 0; i < NOFILE; i++)
    p->ofile[i] = 0;
  memset(p->ofile_cloexec, 0, sizeof(p->ofile_cloexec));
  p->state = UNUSED;
}

// Create a user page table for a given process,
// with no user memory, but with trampoline pages.
pagetable_t
proc_pagetable(struct proc *p)
{
  pagetable_t pagetable;

  // An empty page table.
  pagetable = uvmcreate();
  if(pagetable == 0)
    return NULL;

  // map the trampoline code (for system call return)
  // at the highest user virtual address.
  // only the supervisor uses it, on the way
  // to/from user space, so not PTE_U.
  if(mappages(pagetable, TRAMPOLINE, PGSIZE,
              (uint64)trampoline, PTE_R | PTE_X) < 0){
    uvmfree(pagetable, 0);
    return NULL;
  }

  // map the trapframe just below TRAMPOLINE, for trampoline.S.
  if(mappages(pagetable, TRAPFRAME, PGSIZE,
              (uint64)(p->trapframe), PTE_R | PTE_W) < 0){
    vmunmap(pagetable, TRAMPOLINE, 1, 0);
    uvmfree(pagetable, 0);
    return NULL;
  }

  return pagetable;
}

// Free a process's page table, and free the
// physical memory it refers to.
void
proc_freepagetable(pagetable_t pagetable, uint64 sz)
{
  vmunmap_maybe(pagetable, TRAMPOLINE, 1, 0);
  vmunmap_maybe(pagetable, TRAPFRAME, 1, 0);
  uvmfree(pagetable, sz);
}

static void
proc_freepagetable_nophys(pagetable_t pagetable, uint64 sz)
{
  vmunmap_maybe(pagetable, TRAMPOLINE, 1, 0);
  vmunmap_maybe(pagetable, TRAPFRAME, 1, 0);
  uvmfree_nophys(pagetable, sz);
}

