#define MEMFILE_PAGES_PER_CHUNK 511
#define NMEMFILES 256

struct memfile_chunk {
  struct memfile_chunk *next;
  char *pages[MEMFILE_PAGES_PER_CHUNK];
};

struct {
  struct spinlock lock;
  struct memfile_ref files[NMEMFILES];
} memftable;

static char *
memfile_page(struct file *f, uint pageno, int alloc)
{
  struct memfile_chunk *c = (struct memfile_chunk *)f->mem;
  if(c == 0) {
    if(!alloc)
      return 0;
    c = (struct memfile_chunk *)kalloc();
    if(c == 0)
      return 0;
    memset(c, 0, PGSIZE);
    f->mem = c;
  }

  while(pageno >= MEMFILE_PAGES_PER_CHUNK) {
    pageno -= MEMFILE_PAGES_PER_CHUNK;
    if(c->next == 0) {
      if(!alloc)
        return 0;
      c->next = (struct memfile_chunk *)kalloc();
      if(c->next == 0)
        return 0;
      memset(c->next, 0, PGSIZE);
    }
    c = c->next;
  }

  if(c->pages[pageno] == 0 && alloc) {
    c->pages[pageno] = (char *)kalloc();
    if(c->pages[pageno])
      memset(c->pages[pageno], 0, PGSIZE);
  }
  return c->pages[pageno];
}

static void
memfile_free(void *root)
{
  struct memfile_chunk *c = (struct memfile_chunk *)root;
  while(c) {
    struct memfile_chunk *next = c->next;
    for(int i = 0; i < MEMFILE_PAGES_PER_CHUNK; i++)
      if(c->pages[i])
        kfree(c->pages[i]);
    kfree(c);
    c = next;
  }
}

