filealloc(void)
{
  struct file *f;

  acquire(&ftable.lock);
  for(f = ftable.file; f < ftable.file + NFILE; f++){
    if(f->ref == 0){
      memset(f, 0, sizeof(*f));
      f->ref = 1;
      release(&ftable.lock);
      return f;
    }
  }
  release(&ftable.lock);
  return NULL;
}

// Increment ref count for file f.
struct file*
filedup(struct file *f)
{
  acquire(&ftable.lock);
  if(f->ref < 1)
    panic("filedup");
  f->ref++;
  release(&ftable.lock);
  return f;
}

// Close file f.  (Decrement ref count, close when reaches 0.)
void
fileclose(struct file *f)
{
  struct file ff;
  struct memfile_ref *mr;

  acquire(&ftable.lock);
  if(f->ref < 1) {
    release(&ftable.lock);
    return;
  }
  if(--f->ref > 0){
    release(&ftable.lock);
    return;
  }
  ff = *f;
  f->ref = 0;
  f->type = FD_NONE;
  release(&ftable.lock);

  if(ff.type == FD_PIPE){
    pipeclose(ff.pipe, ff.writable);
  } else if(ff.type == FD_ENTRY){
    eput(ff.ep);
  } else if (ff.type == FD_DEVICE) {
    // nothing to clean up
  } else if (ff.type == FD_EXT4) {
    // path-based: nothing to close
  } else if (ff.type == FD_MEM) {
    mr = ff.mem_ref;
    if (mr) {
      acquire(&memftable.lock);
      if (mr->refs > 0)
        mr->refs--;
      if (mr->refs == 0 && mr->unlinked) {
        memfile_free(mr->root);
        memset(mr, 0, sizeof(*mr));
      }
      release(&memftable.lock);
    } else {
      memfile_free(ff.mem);
    }
  } else if (ff.type == FD_SOCKET) {
    socketclose(ff.sock);
  }
}

