static int
streq(const char *a, const char *b)
{
    int i = 0;
    while (a[i] && b[i]) {
        if (a[i] != b[i])
            return 0;
        i++;
    }
    return a[i] == b[i];
}

static int
append_char(char *out, int cap, int *pos, char ch)
{
    if (*pos >= cap - 1)
        return -1;
    out[(*pos)++] = ch;
    out[*pos] = '\0';
    return 0;
}

static int
append_str(char *out, int cap, int *pos, const char *s)
{
    while (*s) {
        if (append_char(out, cap, pos, *s++) < 0)
            return -1;
    }
    return 0;
}

static int
append_uint(char *out, int cap, int *pos, uint64 v)
{
    char tmp[24];
    int n = 0;

    if (v == 0)
        return append_char(out, cap, pos, '0');
    while (v && n < (int)sizeof(tmp)) {
        tmp[n++] = '0' + (v % 10);
        v /= 10;
    }
    while (n-- > 0) {
        if (append_char(out, cap, pos, tmp[n]) < 0)
            return -1;
    }
    return 0;
}

static int
append_hex_uint(char *out, int cap, int *pos, uint64 v)
{
    const char *hex = "0123456789abcdef";
    char tmp[16];
    int n = 0;

    if (v == 0)
        return append_char(out, cap, pos, '0');
    while (v && n < (int)sizeof(tmp)) {
        tmp[n++] = hex[v & 0xf];
        v >>= 4;
    }
    while (n-- > 0) {
        if (append_char(out, cap, pos, tmp[n]) < 0)
            return -1;
    }
    return 0;
}

static int
append_int(char *out, int cap, int *pos, int v)
{
    if (v < 0) {
        if (append_char(out, cap, pos, '-') < 0)
            return -1;
        return append_uint(out, cap, pos, (uint64)(-(long)v));
    }
    return append_uint(out, cap, pos, v);
}

static int
append_proc_field(char *out, int cap, int *pos, const char *key, uint64 val)
{
    return append_str(out, cap, pos, key) < 0 ||
           append_uint(out, cap, pos, val) < 0 ||
           append_char(out, cap, pos, '\n') < 0 ? -1 : 0;
}

