// kernel/exec_elf.c
//
// M4: static ELF loader for binaries living on the EXT4 image.
//
// xv6's existing exec.c reads from FAT32 via eread(); this one reads from
// lwext4 via ext4_fread(). It targets ET_EXEC / EM_RISCV statically-linked
// binaries plus the contest "basic" PIE ELFs. Those basic ELFs are tagged
// ET_DYN by the toolchain, but are linked from the testsuite's tiny -nostdlib
// runtime and carry no dynamic relocations.
//
// Stack layout follows the Linux SysV psABI start-up convention because
// musl's __libc_start_main / _start_c expect exactly that:
//
//   high addr   |   envp strings + argv strings + AT_RANDOM bytes  |
//               |   ... padding to 16B alignment ...               |
//               |   auxv[]: AT_NULL terminator                     |
//               |   auxv[]: AT_PAGESZ, AT_RANDOM, AT_PHDR, ...     |
//               |   envp[] pointer array, NULL-terminated          |
//               |   argv[] pointer array, NULL-terminated          |
//   low addr SP |   argc                                           |
//
// On success the loader takes over the calling process: pagetable, sz, sp,
// and pc are all swapped, and on return-to-user the trampoline jumps to
// elf.entry. On failure the caller's process is unchanged.

