static int
ext4_supported_exec(const char *path)
{
    ext4_file f;
    ext4_acquire();
    int r = ext4_fopen(&f, path, "rb");
    if (r != EOK) {
        ext4_release();
        return 0;
    }
    struct elfhdr elf;
    size_t got = 0;
    r = ext4_fread(&f, &elf, sizeof(elf), &got);
    ext4_fclose(&f);
    ext4_release();
    if (r != EOK || got != sizeof(elf))
        return 0;
    return elf.magic == ELF_MAGIC
        && (elf.type == ELF_EXEC || elf.type == ELF_DYN)
        && elf.machine == EM_RISCV;
}

