static int
ext4_exec_has_dynamic_segment(const char *path)
{
    ext4_file f;
    struct elfhdr elf;
    struct proghdr ph;
    size_t got = 0;
    int has_dynamic = 0;

    ext4_acquire();
    if (ext4_fopen(&f, path, "rb") != EOK) {
        ext4_release();
        return 0;
    }
    if (ext4_fread(&f, &elf, sizeof(elf), &got) != EOK ||
        got != sizeof(elf) ||
        elf.magic != ELF_MAGIC ||
        elf.machine != EM_RISCV ||
        elf.phnum > 32) {
        ext4_fclose(&f);
        ext4_release();
        return 0;
    }

    for (int i = 0; i < elf.phnum; i++) {
        uint64 off = elf.phoff + (uint64)i * elf.phentsize;
        if (ext4_fseek(&f, off, SEEK_SET) != EOK ||
            ext4_fread(&f, &ph, sizeof(ph), &got) != EOK ||
            got != sizeof(ph))
            break;
        if (ph.type == ELF_PROG_DYNAMIC) {
            has_dynamic = 1;
            break;
        }
    }
    ext4_fclose(&f);
    ext4_release();
    return has_dynamic;
}

