// kernel/ext4_glue.c
//
// Bridge layer between lwext4 (third-party EXT4 driver) and our kernel.
// Provides what lwext4 expects (a block device + malloc/free + assert) by
// wrapping virtio_disk_rw and kalloc.
//
// Strategy notes:
//   * We bypass our own bio.c buffer cache; lwext4 has its own bcache.
//   * Block-device I/O goes one 512-byte sector at a time through a single
//     scratch struct buf. lwext4 batches at the 4 KiB block level above us.
//   * ext4_user_malloc/free serve allocations <= PGSIZE by handing out whole
//     zeroed pages from kalloc. lwext4's hot allocations are block-sized
//     (4 KiB); smaller allocs waste up to a page each but the count is bounded.

#include "include/types.h"
#include "include/param.h"
#include "include/spinlock.h"
#include "include/sleeplock.h"
#include "include/riscv.h"
#include "include/buf.h"
#include "include/printf.h"
#include "include/string.h"
#include "include/kalloc.h"
#include "include/virtio.h"
#include "include/ext4_glue.h"

#include "lwext4/include/ext4.h"
#include "lwext4/include/ext4_blockdev.h"
#include "lwext4/include/ext4_errno.h"

// --- ext4_user_malloc / ext4_user_free ---------------------------------------
//
// lwext4 was compiled with CONFIG_USE_USER_MALLOC=1, so it calls these.
// We satisfy all requests by allocating one full 4 KiB page each. Free
// returns the page to kalloc's freelist. Requests larger than a page are
// rejected (lwext4's largest single alloc is the filesystem block, which is
// 4 KiB on a default mkfs.ext4 image).

void *
ext4_user_malloc(size_t size)
{
    if (size == 0 || size > PGSIZE)
        return 0;
    void *p = kalloc();
    if (p)
        memset(p, 0, PGSIZE);
    return p;
}

void *
ext4_user_calloc(size_t nmemb, size_t size)
{
    size_t total = nmemb * size;
    if (nmemb != 0 && total / nmemb != size)
        return 0;
    if (total == 0 || total > PGSIZE)
        return 0;
    return ext4_user_malloc(total);
}

void *
ext4_user_realloc(void *ptr, size_t size)
{
    // Only used in cold paths. Worst-case implementation: alloc-copy-free.
    void *np = ext4_user_malloc(size);
    if (!np)
        return 0;
    if (ptr) {
        memmove(np, ptr, size < PGSIZE ? size : PGSIZE);
        kfree(ptr);
    }
    return np;
}

void
ext4_user_free(void *ptr)
{
    if (ptr)
        kfree(ptr);
}

// qsort is referenced by lwext4's dir_idx code on the write path. We mount
// read-only, so this is dead code — but the linker still wants resolution.
// Implement a minimal recursion-free version so a stray call wouldn't crash.
void
qsort(void *base, size_t n, size_t sz,
      int (*cmp)(const void *, const void *))
{
    char *b = (char *)base;
    char tmp[256];   // lwext4 sorts small structs; cap matches its largest use
    if (sz > sizeof tmp)
        return;
    for (size_t i = 1; i < n; i++) {
        for (size_t j = i; j > 0 && cmp(b + (j-1)*sz, b + j*sz) > 0; j--) {
            memmove(tmp, b + (j-1)*sz, sz);
            memmove(b + (j-1)*sz, b + j*sz, sz);
            memmove(b + j*sz, tmp, sz);
        }
    }
}

// --- block device shim --------------------------------------------------------
//
// We talk to QEMU virtio-blk via virtio_disk_rw(), which transfers exactly one
// 512-byte sector per call into a struct buf. ph_bsize = 512 mirrors that.
// virtio_disk_rw requires process context (sleeps on disk completion); see
// the comment in ext4_glue_init.

static int blockdev_open(struct ext4_blockdev *bdev)  { (void)bdev; return EOK; }
static int blockdev_close(struct ext4_blockdev *bdev) { (void)bdev; return EOK; }
static int blockdev_lock(struct ext4_blockdev *bdev)  { (void)bdev; return EOK; }
static int blockdev_unlock(struct ext4_blockdev *bdev){ (void)bdev; return EOK; }

static int
blockdev_bread(struct ext4_blockdev *bdev, void *out,
               uint64_t blk_id, uint32_t blk_cnt)
{
    (void)bdev;
    struct buf *b = (struct buf *)kalloc();
    if (!b)
        return ENOMEM;
    uint8_t *dst = (uint8_t *)out;
    for (uint32_t i = 0; i < blk_cnt; i++) {
        memset(b, 0, sizeof(*b));
        b->sectorno = (uint)(blk_id + i);
        b->disk = 0;
        virtio_disk_rw(b, 0);
        memmove(dst + i * BSIZE, b->data, BSIZE);
    }
    kfree(b);
    return EOK;
}

static int
blockdev_bwrite(struct ext4_blockdev *bdev, const void *in,
                uint64_t blk_id, uint32_t blk_cnt)
{
    (void)bdev;
    struct buf *b = (struct buf *)kalloc();
    if (!b)
        return ENOMEM;
    const uint8_t *src = (const uint8_t *)in;
    for (uint32_t i = 0; i < blk_cnt; i++) {
        memset(b, 0, sizeof(*b));
        b->sectorno = (uint)(blk_id + i);
        b->disk = 0;
        memmove(b->data, src + i * BSIZE, BSIZE);
        virtio_disk_rw(b, 1);
    }
    kfree(b);
    return EOK;
}

EXT4_BLOCKDEV_STATIC_INSTANCE(g_bdev,
    /* bsize */ BSIZE,
    /* bcnt  */ 0,            // patched at runtime from disk capacity guess
    blockdev_open, blockdev_bread, blockdev_bwrite,
    blockdev_close, blockdev_lock, blockdev_unlock);

// --- mount --------------------------------------------------------------------

int
ext4_glue_init(void)
{
    int r;

    // ph_bcnt 0 trips lwext4 size checks; lwext4 only uses part_size for the
    // upper bound, so set both to "big enough" for the evaluator's raw images.
    // The actual EXT4 superblock declares the real filesystem size.
    g_bdev.bdif->ph_bcnt = (1ULL << 32) / BSIZE;
    g_bdev.part_size     = g_bdev.bdif->ph_bcnt * BSIZE;

    if ((r = ext4_device_register(&g_bdev, "ext4_fs")) != EOK) {
        printf("[ext4] ext4_device_register failed: %d\n", r);
        return r;
    }

    if ((r = ext4_mount("ext4_fs", "/", false)) != EOK) {
        printf("[ext4] ext4_mount failed: %d\n", r);
        return r;
    }

    return 0;
}

