  else if((which_dev = devintr()) != 0){
    // ok
  } 
  else if((r_scause() == 13 || r_scause() == 15) &&
          r_stval() < TRAPFRAME && r_stval() >= p->sz) {
    uint64 newsz = (r_stval() + PGSIZE) & ~(PGSIZE - 1);
    if (newsz < r_stval() || growproc(newsz - p->sz) < 0)
