static int
fd_ready_read(struct file *f)
{
  if (f == 0 || !f->readable)
    return 0;
  if (f->type == FD_PIPE) {
    struct pipe *pi = f->pipe;
    int ready;
    acquire(&pi->lock);
    ready = (pi->nread != pi->nwrite) || !pi->writeopen;
    release(&pi->lock);
    return ready;
  }
  return 1;
}

static int
fd_ready_write(struct file *f)
{
  if (f == 0 || !f->writable)
    return 0;
  if (f->type == FD_PIPE) {
    struct pipe *pi = f->pipe;
    int ready;
    acquire(&pi->lock);
    ready = pi->readopen && (pi->nwrite != pi->nread + PIPESIZE);
    release(&pi->lock);
    return ready;
  }
  return 1;
}

