int
wait_kernel(int *status, int pid_to_wait, int options)
{
  struct proc *np;
  int havekids, pid;
  struct proc *p = myproc();

  acquire(&p->lock);

  for(;;){
    havekids = 0;
    for(np = proc; np < &proc[NPROC]; np++){
      if(np->parent == p){
        if(pid_to_wait == -1 || np->pid == pid_to_wait) {
          acquire(&np->lock);
          havekids = 1;
          if(np->state == ZOMBIE){
            pid = np->pid;
            if(status != 0)
              *status = np->xstate;
            freeproc(np);
            release(&np->lock);
            release(&p->lock);
            return pid;
          }
          release(&np->lock);
        }
      }
    }

    if(!havekids || p->killed){
      release(&p->lock);
      return -1;
    }

    if(options & 1) {
      release(&p->lock);
      return 0;
    }

    sleep(p, &p->lock);
  }
}

// Create a new process, copying the parent.
// The new process will start executing with the stack provided.
// Returns child's PID on success, -1 on failure.
#define CLONE_VM             0x00000100
#define CLONE_FILES          0x00000400
#define CLONE_SETTLS         0x00080000
#define CLONE_PARENT_SETTID  0x00100000
#define CLONE_CHILD_CLEARTID 0x00200000
#define CLONE_CHILD_SETTID   0x01000000

int
clone(uint64 flags, uint64 stack, uint64 ptid, uint64 tls, uint64 ctid)
{
  int i, pid;
  struct proc *np;
  struct proc *p = myproc();

  // Allocate process.
  if((np = allocproc()) == NULL){
    return -1;
  }

  if((flags & CLONE_VM) != 0) {
    if(uvmshare(p->pagetable, np->pagetable, np->kpagetable, p->sz) < 0){
      freeproc(np);
      release(&np->lock);
      return -1;
    }
    np->is_thread = 1;
    np->vm_leader = p->vm_leader ? p->vm_leader : p;
  } else if(uvmcopy(p->pagetable, np->pagetable, np->kpagetable, p->sz) < 0){
    freeproc(np);
    release(&np->lock);
    return -1;
  }
  np->sz = p->sz;
  np->brk = p->brk;
  np->clear_child_tid = (flags & CLONE_CHILD_CLEARTID) ? ctid : 0;
  np->sigmask = p->sigmask;
  np->sigpending = 0;
  memmove(np->sigactions, p->sigactions, sizeof(p->sigactions));
  np->sigactive = 0;
  np->sigsavedmask = 0;
  memset(&np->sigtf, 0, sizeof(np->sigtf));
  memmove(np->mmap_areas, p->mmap_areas, sizeof(p->mmap_areas));
  memset(np->itimers, 0, sizeof(np->itimers));
  memset(np->itimer_deadline, 0, sizeof(np->itimer_deadline));
  np->nofile_limit = p->nofile_limit;
  np->stack_limit = p->stack_limit;
  np->uid = p->uid;
  np->euid = p->euid;
  np->suid = p->suid;
  np->gid = p->gid;
  np->egid = p->egid;
  np->sgid = p->sgid;
  np->ngroups = p->ngroups;
  memmove(np->groups, p->groups, sizeof(p->groups));
  np->umask = p->umask;
  np->parent = p;

  // copy saved user registers.
  *(np->trapframe) = *(p->trapframe);

  // --- clone 的核心修改 ---
  // 1. 将子进程的返回寄存器(a0)设置为0。
  np->trapframe->a0 = 0;

  // 2. 如果用户提供了新的栈地址，就使用它。
  //    注意：我们不修改 epc！子进程会从 syscall 返回，和父进程一样。
  if (stack != 0) {
    np->trapframe->sp = stack;
  }
  if (flags & CLONE_SETTLS)
    np->trapframe->tp = tls;

  // Each proc has its own fd slots, so every copied slot must hold a reference
  // even when CLONE_FILES requests shared file descriptors.
  for(i = 0; i < NOFILE; i++) {
    if(p->ofile[i] == 0)
      continue;
    np->ofile[i] = filedup(p->ofile[i]);
    np->ofile_cloexec[i] = p->ofile_cloexec[i];
  }
  np->cwd = 0;
  strncpy(np->cwd_path, p->cwd_path, MAXPATH);

  safestrcpy(np->name, p->name, sizeof(p->name));

  pid = np->pid;
  if ((flags & CLONE_PARENT_SETTID) && ptid)
    copyout2(ptid, (char *)&pid, sizeof(pid));
  if ((flags & CLONE_CHILD_SETTID) && ctid)
    copyout(np->pagetable, ctid, (char *)&pid, sizeof(pid));

  np->state = RUNNABLE;

  release(&np->lock);

  return pid;
}
// Per-CPU process scheduler.
// Each CPU calls scheduler() after setting itself up.
// Scheduler never returns.  It loops, doing:
//  - choose a process to run.
//  - swtch to start running that process.
//  - eventually that process transfers control
//    via swtch back to the scheduler.
void
scheduler(void)
{
  struct proc *p;
  struct cpu *c = mycpu();
  extern pagetable_t kernel_pagetable;

  c->proc = 0;
  for(;;){
    // Avoid deadlock by ensuring that devices can interrupt.
    intr_on();
    // printf("s:%d ", intr_get());  // 加上探针debug
    int found = 0;
    for(p = proc; p < &proc[NPROC]; p++) {
      acquire(&p->lock);
      if(p->state == RUNNABLE) {
        // Switch to chosen process.  It is the process's job
        // to release its lock and then reacquire it
        // before jumping back to us.
        // printf("[scheduler]found runnable proc with pid: %d\n", p->pid);
        p->state = RUNNING;
        c->proc = p;
        w_satp(MAKE_SATP(p->kpagetable));
        sfence_vma();
        swtch(&c->context, &p->context);
        w_satp(MAKE_SATP(kernel_pagetable));
        sfence_vma();
        // Process is done running for now.
        // It should have changed its p->state before coming back.
        c->proc = 0;

        found = 1;
      }
      release(&p->lock);
    }
    if(found == 0) {
      intr_on();
      asm volatile("wfi");
    }
  }
}

// Switch to scheduler.  Must hold only p->lock
// and have changed proc->state. Saves and restores
// intena because intena is a property of this
// kernel thread, not this CPU. It should
// be proc->intena and proc->noff, but that would
// break in the few places where a lock is held but
// there's no process.
void
sched(void)
{
  int intena;
  struct proc *p = myproc();

  if(!holding(&p->lock))
    panic("sched p->lock");
  if(mycpu()->noff != 1)
    panic("sched locks");
  if(p->state == RUNNING)
    panic("sched running");
  if(intr_get())
    panic("sched interruptible");

  intena = mycpu()->intena;
  swtch(&p->context, &mycpu()->context);
  mycpu()->intena = intena;
}

// Give up the CPU for one scheduling round.
void
yield(void)
{
  struct proc *p = myproc();
  acquire(&p->lock);
  p->state = RUNNABLE;
  sched();
  release(&p->lock);
}

// A fork child's very first scheduling by scheduler()
// will swtch to forkret.
void
forkret(void)
{
  // printf("run in forkret\n");
  static int first = 1;

  // Still holding p->lock from scheduler.
  release(&myproc()->lock);

  if (first) {
    // File system initialization must be run in the context of a
    // regular process (e.g., because it calls sleep), and thus cannot
    // be run from main().
    first = 0;
    // M6 stub: in process context, run the test scaffolding then shut
    // the machine down. runtests() never returns. Remove this once a
    // real userspace path (M3 syscalls + M4 musl loader) is in place.
    extern void runtests(void);
    runtests();
    // not reached
  }

  usertrapret();
}

// Atomically release lock and sleep on chan.
// Reacquires lock when awakened.
void
sleep(void *chan, struct spinlock *lk)
{
  struct proc *p = myproc();

  // Must acquire p->lock in order to
  // change p->state and then call sched.
  // Once we hold p->lock, we can be
  // guaranteed that we won't miss any wakeup
  // (wakeup locks p->lock),
  // so it's okay to release lk.
  if(lk != &p->lock){  //DOC: sleeplock0
    acquire(&p->lock);  //DOC: sleeplock1
    release(lk);
  }

  // Go to sleep.
  p->chan = chan;
  p->state = SLEEPING;

  sched();

  // Tidy up.
  p->chan = 0;

  // Reacquire original lock.
  if(lk != &p->lock){
    release(&p->lock);
    acquire(lk);
  }
}

