static int
open_interp_file(ext4_file *f, const char *exec_path,
                 const char *interp_path, char *resolved, int resolved_cap)
{
    const char *base = path_base_name(interp_path);
    const char *root = exec_abi_root(exec_path);

    if (try_open_interp(f, interp_path, resolved, resolved_cap) == 0)
        return 0;

    if (try_open_interp_under(f, root, base, resolved, resolved_cap) == 0)
        return 0;

    if (path_has_suffix(interp_path, "ld-musl-riscv64.so.1") ||
        path_has_suffix(interp_path, "ld-musl-riscv64-sf.so.1")) {
        if (try_open_interp_under(f, root, "libc.so", resolved,
                                  resolved_cap) == 0)
            return 0;
        if (try_open_interp_under(f, "/musl", base, resolved,
                                  resolved_cap) == 0)
            return 0;
        if (try_open_interp_under(f, "/musl", "libc.so", resolved,
                                  resolved_cap) == 0)
            return 0;
