static struct exec_cache_slot *
get_exec_cache(const char *path, ext4_file *f)
{
    if (!is_cached_exec_path(path))
        return 0;

    uint64 size = ext4_fsize(f);
    if (size == 0 || size > EXEC_CACHE_MAX)
        return 0;

    for (int i = 0; i < EXEC_CACHE_SLOTS; i++) {
        if (exec_cache[i].valid && strncmp(exec_cache[i].path, path, MAXPATH) == 0)
            return &exec_cache[i];
    }

    struct exec_cache_slot *slot = 0;
    for (int i = 0; i < EXEC_CACHE_SLOTS; i++) {
        if (!exec_cache[i].valid) {
            slot = &exec_cache[i];
            break;
        }
    }
    if (slot == 0)
        slot = &exec_cache[0];

    slot->valid = 0;
    slot->shared_npages = 0;
    slot->share_pages = is_shared_exec_path(path);

    if (ext4_fseek(f, 0, SEEK_SET) != EOK)
        return 0;
    uint64 done = 0;
    while (done < size) {
        uint64 chunk = EXEC_EXT4_READ_CHUNK;
        if (chunk > size - done)
            chunk = size - done;
        size_t got = 0;
        if (ext4_fread(f, slot->data + done, chunk, &got) != EOK ||
            got != chunk)
            return 0;
        done += chunk;
    }

    slot->valid = 1;
    slot->size = size;
    safestrcpy(slot->path, path, sizeof(slot->path));
    return slot;
}

static int
read_full(ext4_file *f, void *buf, uint64_t off, size_t want)
{
    if (active_exec_data != 0) {
        if (off + want < off || off + want > active_exec_size)
            return -1;
        memmove(buf, active_exec_data + off, want);
        return 0;
    }
    if (ext4_fseek(f, off, SEEK_SET) != EOK)
        return -1;
    size_t got = 0;
    if (ext4_fread(f, buf, want, &got) != EOK)
        return -1;
    if (got != want)
        return -1;
    return 0;
}

// Load one PT_LOAD program header from ELF file into the new user pagetable.
// We've already uvmalloc'd up to ph->vaddr + ph->memsz. The memsz-filesz tail
// is zeroed because uvmalloc returns zero pages. ph->vaddr does NOT have to
// be page-aligned — the loop walks one page at a time using page_off so
// musl's typical R/W segment starting at 0x11ff0 just works.
static int
load_phdr(pagetable_t pagetable, ext4_file *f, const struct proghdr *ph)
{
    if (ph->filesz == 0)
        return 0;

    uint64 remaining = ph->filesz;
    uint64 va = ph->vaddr;

    while (remaining > 0) {
        uint64 chunk = ph->filesz > (1024 * 1024) ? PGSIZE : sizeof(loadbuf);
        uint64 off = ph->off + (ph->filesz - remaining);
        if (chunk > remaining)
            chunk = remaining;

        size_t got = 0;
        if (active_exec_data != 0) {
            if (off + chunk < off || off + chunk > active_exec_size)
                goto bad;
            memmove(loadbuf, active_exec_data + off, chunk);
            got = chunk;
        } else {
            if (ext4_fseek(f, off, SEEK_SET) != EOK)
                goto bad;
            int rr = ext4_fread(f, loadbuf, chunk, &got);
            if (rr != EOK || got != chunk) {
                printf("[exec_elf] fread failed off=%p chunk=%d got=%d\n",
                       off, (int)chunk, (int)got);
                goto bad;
            }
        }
        if (copyout(pagetable, va, loadbuf, got) < 0) {
            printf("[exec_elf] copyout failed va=%p got=%d\n", va, (int)got);
            goto bad;
        }

        va        += chunk;
        remaining -= chunk;
    }
    return 0;

bad:
    return -1;
}

static int
load_phdr_at(pagetable_t pagetable, ext4_file *f, const struct proghdr *ph,
             uint64 load_bias)
{
    struct proghdr bph = *ph;

    bph.vaddr = ph->vaddr + load_bias;
    return load_phdr(pagetable, f, &bph);
}

static int
elf_load_perm(uint32 flags, int user)
{
    int perm = user ? PTE_U : 0;

    if (flags & ELF_PROG_FLAG_READ)
