static struct exec_shared_page *
create_shared_page(struct exec_cache_slot *slot,
                   const struct proghdr *ph,
                   uint64 page_va,
                   int perm)
{
    if (slot->shared_npages >= EXEC_CACHE_MAX_PAGES)
        return 0;

    char *mem = kalloc();
    if (mem == 0)
        return 0;
    memset(mem, 0, PGSIZE);

    uint64 page_end = page_va + PGSIZE;
    uint64 file_start = ph->vaddr;
    uint64 file_end = ph->vaddr + ph->filesz;
    uint64 copy_start = page_va > file_start ? page_va : file_start;
    uint64 copy_end = page_end < file_end ? page_end : file_end;

    if (copy_start < copy_end) {
        uint64 file_off = ph->off + (copy_start - ph->vaddr);
        uint64 n = copy_end - copy_start;
        if (file_off + n < file_off || file_off + n > slot->size) {
            kfree(mem);
            return 0;
        }
        memmove(mem + (copy_start - page_va), slot->data + file_off, n);
    }

    struct exec_shared_page *page = &slot->shared_pages[slot->shared_npages++];
    page->va = page_va;
    page->pa = mem;
    page->perm = perm | PTE_SHARED;
    return page;
}

