// Install console fds on the current process (initproc).
static void
install_console_fds(void)
{
    install_console_fds_on(myproc());
}

static int
kernel_spawn_argv(const char *path, const char *name, const char *cwd,
                  char *const argv[], char *const envp[])
{
    struct proc *np = allocproc();
    if (!np)
        return -1;

    np->parent = myproc();

    // Give the child console file descriptors
    install_console_fds_on(np);

    // No FAT32 cwd; EXT4 path resolution uses cwd_path (set below).
    np->cwd = 0;
    if (cwd) {
        safestrcpy(np->cwd_path, cwd, sizeof(np->cwd_path));
    } else {
        np->cwd_path[0] = '/';
        np->cwd_path[1] = '\0';
    }

    // Release np->lock before ELF loading — ext4 disk I/O sleeps,
    // which is incompatible with holding a spinlock (sched requires noff==1).
    // np is in USED state and not yet RUNNABLE, so no other code will touch it.
    release(&np->lock);

    if (exec_elf_ext4_proc(np, path, argv, envp) < 0) {
        acquire(&np->lock);
        for (int fd = 0; fd < NOFILE; fd++) {
            if (np->ofile[fd]) {
                fileclose(np->ofile[fd]);
                np->ofile[fd] = 0;
            }
        }
        freeproc(np);
        release(&np->lock);
        return -1;
    }

    acquire(&np->lock);
    safestrcpy(np->name, name, sizeof(np->name));
    int pid = np->pid;
    np->state = RUNNABLE;
    release(&np->lock);

    return pid;
}

static int
__attribute__((unused))
kernel_spawn_argv_capture(const char *path, const char *name, const char *cwd,
                          char *const argv[], char *const envp[],
                          struct file *out)
{
    struct proc *np = allocproc();
    if (!np)
        return -1;

    np->parent = myproc();
    install_console_fds_on(np);

    if (out) {
        if (np->ofile[1]) {
            fileclose(np->ofile[1]);
            np->ofile[1] = 0;
        }
        if (np->ofile[2]) {
            fileclose(np->ofile[2]);
            np->ofile[2] = 0;
        }
        np->ofile[1] = filedup(out);
        np->ofile[2] = filedup(out);
    }

    np->cwd = 0;
    if (cwd) {
        safestrcpy(np->cwd_path, cwd, sizeof(np->cwd_path));
    } else {
        np->cwd_path[0] = '/';
        np->cwd_path[1] = '\0';
    }

    release(&np->lock);

    if (exec_elf_ext4_proc(np, path, argv, envp) < 0) {
        acquire(&np->lock);
        for (int fd = 0; fd < NOFILE; fd++) {
            if (np->ofile[fd]) {
                fileclose(np->ofile[fd]);
                np->ofile[fd] = 0;
            }
