void
watchdog_check(void)
{
    if (global_deadline != 0 && r_time() >= global_deadline) {
        printf("\n[watchdog] global deadline exceeded, forcing shutdown\n");
        sbi_shutdown();
        for (;;) asm volatile("wfi");
    }
    int pid = watchdog_pid;
    if (pid > 0 && r_time() >= watchdog_deadline) {
        watchdog_pid = 0;
        kill(pid);
    }
}

static int
ltp_budget_exhausted(void)
{
    uint64 now;

    if (global_deadline == 0)
        return 0;
    now = r_time();
    return now + LTP_STOP_RESERVE_CYCLES >= global_deadline;
}

// Reap zombie children and kill live orphans of initproc so the process
// table doesn't fill up across tests.
static void
reap_zombies(void)
{
    extern struct proc proc[];
    extern struct proc *initproc;

    for (int pass = 0; pass < 4; pass++) {
        int touched = 0;

        for (struct proc *pp = proc; pp < &proc[NPROC]; pp++) {
            if (pp == initproc)
                continue;
            acquire(&pp->lock);
            if (pp->state == ZOMBIE) {
                freeproc(pp);
                touched = 1;
                release(&pp->lock);
                continue;
            }
            if (pp->state != UNUSED) {
                pp->killed = 1;
                if (pp->termsig == 0)
                    pp->termsig = 15;
                if (pp->state == SLEEPING)
                    pp->state = RUNNABLE;
                touched = 1;
            }
            release(&pp->lock);
        }
        if (!touched)
            break;
        yield();
    }
}

