static int
read_text_file(const char *path, char *buf, int cap)
{
    ext4_file f;
    uint64 size;
    int total = 0;

    if (cap <= 0)
        return -1;
    buf[0] = 0;
    ext4_acquire();
    int r = ext4_fopen(&f, path, "rb");
    if (r != EOK) {
        ext4_release();
        return -1;
    }
    size = ext4_fsize(&f);
    if (size >= (uint64)cap)
        size = cap - 1;
    while (total < (int)size) {
        uint64 want = size - total;
        size_t got = 0;

        if (want > 512)
            want = 512;
        r = ext4_fread(&f, buf + total, want, &got);
        if (r != EOK)
            break;
        if (got == 0)
            break;
        total += got;
    }
    ext4_fclose(&f);
    ext4_release();
    if (r != EOK)
        return -1;
    buf[total] = 0;
    return total;
}

static int
append_text(char *out, int cap, int *pos, const char *text)
{
    for (int i = 0; text[i]; i++) {
        if (*pos >= cap - 1)
            return -1;
        out[(*pos)++] = text[i];
    }
    out[*pos] = 0;
    return 0;
}

static int
replace_text_once_or_more(char *out, int cap, const char *in,
                          const char *from, const char *to)
{
    int changed = 0;
    int pos = 0;
    int flen = strlen(from);

    out[0] = 0;
    for (int i = 0; in[i]; ) {
        if (flen > 0 && strncmp(in + i, from, flen) == 0) {
            if (append_text(out, cap, &pos, to) < 0)
                return -1;
            i += flen;
            changed = 1;
        } else {
            if (pos >= cap - 1)
                return -1;
            out[pos++] = in[i++];
            out[pos] = 0;
        }
    }
    return changed;
}

static int
build_group_marker(char *out, int cap, const char *kind,
                   const char *group, const char *abi_name)
{
    int pos = 0;

    out[0] = 0;
    if (append_text(out, cap, &pos, "#### OS COMP TEST GROUP ") < 0 ||
        append_text(out, cap, &pos, kind) < 0 ||
        append_text(out, cap, &pos, " ") < 0 ||
        append_text(out, cap, &pos, group) < 0)
        return -1;
    if (abi_name != 0) {
        if (append_text(out, cap, &pos, "-") < 0 ||
            append_text(out, cap, &pos, abi_name) < 0)
            return -1;
    }
    return append_text(out, cap, &pos, " ####");
}

