// kernel/main_la.c
//
// LoongArch64 bring-up entry for the evaluator. The basic runner entered from
// here loads real LoongArch user ELFs from the virtio/ext4 test image and
// handles their Linux-style syscalls in kernel/la_basic.c.
//
// UART base: physical 0x1fe001e0, accessed through the unpaged direct
// window DMW1 at virtual 0x9000_0000_1fe0_01e0.

static volatile unsigned char *const UART =
    (volatile unsigned char *)0x900000001fe001e0UL;
static volatile unsigned char *const GED_SLEEP_CTL =
    (volatile unsigned char *)0x90000000100e001cUL;

#define GED_S5_SLEEP 0x34
#define LA_ECODE_SYS 0xbUL

volatile unsigned long la_saved_kernel_sp;
volatile unsigned long la_saved_kernel_ra;
volatile unsigned long la_saved_kernel_fp;
volatile unsigned long la_saved_kernel_s0;
volatile unsigned long la_saved_kernel_s1;
volatile unsigned long la_saved_kernel_s2;
volatile unsigned long la_saved_kernel_s3;
volatile unsigned long la_saved_kernel_s4;
volatile unsigned long la_saved_kernel_s5;
volatile unsigned long la_saved_kernel_s6;
volatile unsigned long la_saved_kernel_s7;
volatile unsigned long la_saved_kernel_s8;

volatile unsigned long la_saved_user_a0;
volatile unsigned long la_saved_user_a7;
volatile unsigned long la_saved_estat;
volatile unsigned long la_saved_era;
volatile unsigned long la_saved_prmd;
volatile unsigned long la_saved_crmd;
volatile unsigned long la_smoke_ok;

extern int la_basic_main(void);

static void
la_putc(char c)
{
    if (c == '\n')
        *UART = '\r';
    *UART = (unsigned char)c;
}

static void
la_puts(const char *s)
{
    while (*s)
        la_putc(*s++);
}

static void
la_shutdown(void)
{
    *GED_SLEEP_CTL = GED_S5_SLEEP;
    for (;;)
        __asm__ volatile("idle 0");
}

void
la_handle_smoke_trap(void)
{
    unsigned long ecode = (la_saved_estat >> 16) & 0x3f;

    la_smoke_ok = (ecode == LA_ECODE_SYS &&
                   la_saved_user_a0 == 0x2a &&
                   la_saved_user_a7 == 0x1234);
}

void
la_main(void)
{
    la_puts("[kernel-la] LoongArch64 bring-up kernel booted\n");
    la_puts("[kernel-la] starting real LA runner\n");
    la_basic_main();

    la_puts("\n[kernel-la] done, shutting down.\n");
    la_shutdown();
}

