void
la_console_puthex(la_u64 x)
{
    static const char digits[] = "0123456789abcdef";

    la_console_puts("0x");
    for (int i = 60; i >= 0; i -= 4)
        la_console_putc(digits[(x >> i) & 0xf]);
}

void
la_console_putdec(la_i64 x)
{
    char buf[32];
    int i = 0;
    la_u64 u;

    if (x < 0) {
        la_console_putc('-');
        u = (la_u64)(-x);
    } else {
        u = (la_u64)x;
    }
    do {
        buf[i++] = '0' + (u % 10);
        u /= 10;
    } while (u);
    while (i)
        la_console_putc(buf[--i]);
}

void *
memset(void *dst, int c, unsigned long n)
{
    unsigned char *d = dst;
    unsigned long word = (unsigned char)c;

    word |= word << 8;
    word |= word << 16;
    word |= word << 32;
    while (n && ((unsigned long)d & (sizeof(unsigned long) - 1))) {
        *d++ = (unsigned char)c;
        n--;
    }
    while (n >= sizeof(unsigned long)) {
        *(unsigned long *)d = word;
        d += sizeof(unsigned long);
        n -= sizeof(unsigned long);
    }
    while (n--)
        *d++ = (unsigned char)c;
    return dst;
}

void *
memmove(void *dst, const void *src, unsigned long n)
{
    unsigned char *d = dst;
    const unsigned char *s = src;
    if (s < d && s + n > d) {
        s += n;
        d += n;
        while (n && ((unsigned long)d & (sizeof(unsigned long) - 1))) {
            *--d = *--s;
            n--;
        }
        while (n >= sizeof(unsigned long) &&
               (((unsigned long)s & (sizeof(unsigned long) - 1)) == 0)) {
            s -= sizeof(unsigned long);
            d -= sizeof(unsigned long);
            *(unsigned long *)d = *(const unsigned long *)s;
            n -= sizeof(unsigned long);
        }
        while (n--)
            *--d = *--s;
    } else {
        while (n && ((unsigned long)d & (sizeof(unsigned long) - 1))) {
            *d++ = *s++;
            n--;
        }
        while (n >= sizeof(unsigned long) &&
               (((unsigned long)s & (sizeof(unsigned long) - 1)) == 0)) {
            *(unsigned long *)d = *(const unsigned long *)s;
            d += sizeof(unsigned long);
            s += sizeof(unsigned long);
            n -= sizeof(unsigned long);
        }
        while (n--)
            *d++ = *s++;
    }
    return dst;
}

void *
memcpy(void *dst, const void *src, unsigned long n)
{
    return memmove(dst, src, n);
}

int
memcmp(const void *a, const void *b, unsigned long n)
{
    const unsigned char *p = a;
    const unsigned char *q = b;
    while (n--) {
        if (*p != *q)
            return *p - *q;
        p++;
        q++;
    }
    return 0;
}

unsigned long
strlen(const char *s)
{
    unsigned long n = 0;
    while (s[n])
        n++;
    return n;
}

int
strcmp(const char *a, const char *b)
{
    while (*a && *a == *b) {
        a++;
        b++;
    }
    return (unsigned char)*a - (unsigned char)*b;
}

int
strncmp(const char *a, const char *b, unsigned long n)
{
    while (n && *a && *a == *b) {
        a++;
        b++;
        n--;
    }
    if (n == 0)
        return 0;
    return (unsigned char)*a - (unsigned char)*b;
}

char *
strcpy(char *dst, const char *src)
{
    char *ret = dst;
    while ((*dst++ = *src++) != 0)
        ;
    return ret;
}

char *
strncpy(char *dst, const char *src, int n)
{
    char *ret = dst;
    while (n > 0 && *src) {
        *dst++ = *src++;
        n--;
    }
    while (n-- > 0)
        *dst++ = 0;
    return ret;
}

char *
strchr(const char *s, int c)
{
    while (*s) {
        if (*s == (char)c)
            return (char *)s;
        s++;
    }
    return c == 0 ? (char *)s : 0;
}

void
qsort(void *base, unsigned long n, unsigned long sz,
      int (*cmp)(const void *, const void *))
{
    unsigned char tmp[256];
    unsigned char *b = base;

    if (sz > sizeof(tmp))
        return;
    for (unsigned long i = 1; i < n; i++) {
        for (unsigned long j = i; j > 0 &&
             cmp(b + (j - 1) * sz, b + j * sz) > 0; j--) {
            memmove(tmp, b + (j - 1) * sz, sz);
            memmove(b + (j - 1) * sz, b + j * sz, sz);
            memmove(b + j * sz, tmp, sz);
        }
    }
}

