struct spinlock tickslock;
uint ticks;

void timerinit() {
    initlock(&tickslock, "time");
    #ifdef DEBUG
    printf("timerinit\n");
    #endif
}

void
set_next_timeout() {
    // There is a very strange bug,
    // if comment the `printf` line below
    // the timer will not work.

    // this bug seems to disappear automatically
    // printf("");
    sbi_set_timer(r_time() + INTERVAL);
}

extern void watchdog_check(void);

void timer_tick() {
    acquire(&tickslock);
    ticks++;
    wakeup(&ticks);
    release(&tickslock);
    proc_itimer_tick();
    watchdog_check();
    set_next_timeout();
}

  int i, pid;
  struct proc *np;
  struct proc *p = myproc();

  // Allocate process.
  if((np = allocproc()) == NULL){
    return -1;
  }

  // Copy user memory from parent to child.
  if(uvmcopy(p->pagetable, np->pagetable, np->kpagetable, p->sz) < 0){
    freeproc(np);
    release(&np->lock);
    return -1;
  }
  np->sz = p->sz;
  np->brk = p->brk;
  np->clear_child_tid = 0;
  np->is_thread = 0;
  np->sigmask = p->sigmask;
  np->sigpending = 0;
  memmove(np->sigactions, p->sigactions, sizeof(p->sigactions));
  np->sigactive = 0;
  np->sigsavedmask = 0;
  memset(&np->sigtf, 0, sizeof(np->sigtf));
  memmove(np->mmap_areas, p->mmap_areas, sizeof(p->mmap_areas));
  memset(np->itimers, 0, sizeof(np->itimers));
  memset(np->itimer_deadline, 0, sizeof(np->itimer_deadline));
  np->nofile_limit = p->nofile_limit;
  np->stack_limit = p->stack_limit;
  np->uid = p->uid;
  np->euid = p->euid;
  np->suid = p->suid;
  np->gid = p->gid;
  np->egid = p->egid;
  np->sgid = p->sgid;
  np->ngroups = p->ngroups;
  memmove(np->groups, p->groups, sizeof(p->groups));
  np->umask = p->umask;

  np->parent = p;

  // copy tracing mask from parent.
  np->tmask = p->tmask;

  // copy saved user registers.
  *(np->trapframe) = *(p->trapframe);

  // Cause fork to return 0 in the child.
  np->trapframe->a0 = 0;

  // increment reference counts on open file descriptors.
  for(i = 0; i < NOFILE; i++)
    if(p->ofile[i]) {
      np->ofile[i] = filedup(p->ofile[i]);
      np->ofile_cloexec[i] = p->ofile_cloexec[i];
    }
  np->cwd = 0;
  strncpy(np->cwd_path, p->cwd_path, MAXPATH);

  safestrcpy(np->name, p->name, sizeof(p->name));

  pid = np->pid;

  np->state = RUNNABLE;

  release(&np->lock);

  return pid;
}

// Pass p's abandoned children to init.
// Caller must hold p->lock.
void
reparent(struct proc *p)
{
  struct proc *pp;

  for(pp = proc; pp < &proc[NPROC]; pp++){
    // this code uses pp->parent without holding pp->lock.
    // acquiring the lock first could cause a deadlock
    // if pp or a child of pp were also in exit()
    // and about to try to lock p.
    if(pp->parent == p){
      // pp->parent can't change between the check and the acquire()
      // because only the parent changes it, and we're the parent.
      acquire(&pp->lock);
      pp->parent = initproc;
      // we should wake up init here, but that would require
      // initproc->lock, which would be a deadlock, since we hold
      // the lock on one of init's children (pp). this is why
      // exit() always wakes init (before acquiring any locks).
      release(&pp->lock);
    }
  }
}

// Exit the current process.  Does not return.
// An exited process remains in the zombie state
// until its parent calls wait().
void

void
exit(int status)
{
  struct proc *p = myproc();

  if(p == initproc) {
    printf("[exit] initproc exiting with status=%d, shutting down\n", status);
    sbi_shutdown();
    for(;;) ;
  }

  if(p->clear_child_tid) {
    int zero = 0;
    copyout(p->pagetable, p->clear_child_tid, (char *)&zero, sizeof(zero));
    wakeup((void *)p->clear_child_tid);
  }

  if(!p->is_thread) {
    for(struct proc *q = proc; q < &proc[NPROC]; q++) {
      if(q != p && q->vm_leader == p)
        q->killed = 1;
    }
  }

  // A CLONE_VM thread shares process resources; SYS_exit only terminates
  // this schedulable thread, not the whole process file table.
  if(!p->is_thread) {
    for(int fd = 0; fd < NOFILE; fd++){
      if(p->ofile[fd]){
        struct file *f = p->ofile[fd];
        fileclose(f);
        p->ofile[fd] = 0;
      }
    }
  }

  if (!p->is_thread)
    p->cwd = 0;

  // we might re-parent a child to init. we can't be precise about
  // waking up init, since we can't acquire its lock once we've
  // acquired any other proc lock. so wake up init whether that's
  // necessary or not. init may miss this wakeup, but that seems
  // harmless.
  acquire(&initproc->lock);
  wakeup1(initproc);
  release(&initproc->lock);

  // grab a copy of p->parent, to ensure that we unlock the same
  // parent we locked. in case our parent gives us away to init while
  // we're waiting for the parent lock. we may then race with an
  // exiting parent, but the result will be a harmless spurious wakeup
  // to a dead or wrong process; proc structs are never re-allocated
  // as anything else.
  acquire(&p->lock);
  struct proc *original_parent = p->parent;
  release(&p->lock);

  // we need the parent's lock in order to wake it up from wait().
  // the parent-then-child rule says we have to lock it first.
  acquire(&original_parent->lock);
  // 添加times修改 ADD THESE LINES to pass the child's times to its parent
  original_parent->cutime += p->utime;
  original_parent->cstime += p->stime;
  acquire(&p->lock);

  // Give any children to init.
  if(!p->is_thread)
    reparent(p);

  // Make the zombie visible before waking the parent.  libc-test's
  // runtest waits for SIGCHLD and then immediately waitpid()s; if the
  // wakeup races ahead of this state change it falls back to its timeout.
  p->xstate = p->termsig ? p->termsig : (status << 8);
  p->state = ZOMBIE;

  // Parent might be sleeping in wait().
  if(original_parent->sigactions[17].handler != 0 &&
     original_parent->sigactions[17].handler != 1) {
    original_parent->sigpending |= 1ULL << (17 - 1);
    if(original_parent->state == SLEEPING)
      original_parent->state = RUNNABLE;
  }
  wakeup1(original_parent);

  release(&original_parent->lock);

  // Jump into the scheduler, never to return.
  sched();
  panic("zombie exit");
}

