    struct memfile_ref *mr = &memftable.files[i];
    if (mr->path[0] && !mr->unlinked &&
        memfile_is_direct_child_locked(path, mr->path)) {
      release(&memftable.lock);
      return -1;
    }
  }
  for (int i = 0; i < NMEMFILES; i++) {
    struct memfile_ref *mr = &memftable.files[i];
    if (mr->path[0] && !mr->unlinked && strncmp(mr->path, path, MAXPATH) == 0) {
      if (!mr->is_dir) {
        release(&memftable.lock);
        return -1;
      }
      memset(mr, 0, sizeof(*mr));
      release(&memftable.lock);
      return 0;
    }
  }
  release(&memftable.lock);
  return -1;
}

