int
memfile_read_kernel(struct file *f, char *buf, int n, uint off)
{
  if (f == 0 || f->type != FD_MEM || n < 0)
    return -1;

  void *oldroot = 0;
  uint oldsize = 0;
  if (f->mem_ref) {
    oldroot = f->mem;
    oldsize = f->mem_size;
    f->mem = f->mem_ref->root;
    f->mem_size = f->mem_ref->size;
  }

  int total = 0;
  while (total < n && off < f->mem_size) {
    uint pageno = off / PGSIZE;
    uint pageoff = off % PGSIZE;
    int chunk = PGSIZE - pageoff;
    if (chunk > n - total)
      chunk = n - total;
    if (chunk > (int)(f->mem_size - off))
      chunk = f->mem_size - off;
    char *page = memfile_page(f, pageno, 0);
    if (page == 0)
      memset(buf + total, 0, chunk);
    else
      memmove(buf + total, page + pageoff, chunk);
    off += chunk;
    total += chunk;
  }

  if (f->mem_ref) {
    f->mem = oldroot;
    f->mem_size = oldsize;
  }
  return total;
}

int
memfile_write_kernel(struct file *f, const char *buf, int n)
{
  if (f == 0 || f->type != FD_MEM || n < 0)
    return -1;

  int total = 0;
  while (total < n) {
    uint pageno = f->off / PGSIZE;
    uint pageoff = f->off % PGSIZE;
    int chunk = PGSIZE - pageoff;
    if (chunk > n - total)
      chunk = n - total;
    char *page = memfile_page(f, pageno, 1);
    if (page == 0)
      break;
    memmove(page + pageoff, buf + total, chunk);
    f->off += chunk;
    total += chunk;
    if (f->off > f->mem_size)
      f->mem_size = f->off;
  }
  return total;
}

