// Mutual exclusion spin locks.


#include "include/types.h"
#include "include/param.h"
#include "include/memlayout.h"
#include "include/spinlock.h"
#include "include/riscv.h"
#include "include/proc.h"
#include "include/intr.h"
#include "include/printf.h"

void
initlock(struct spinlock *lk, char *name)
{
  lk->name = name;
  lk->locked = 0;
  lk->cpu = 0;
}

// Acquire the lock.
// Loops (spins) until the lock is acquired.
void
acquire(struct spinlock *lk)
{
  push_off(); // disable interrupts to avoid deadlock.
  if(holding(lk))
    panic("acquire");

  // On RISC-V, sync_lock_test_and_set turns into an atomic swap:
  //   a5 = 1
  //   s1 = &lk->locked
  //   amoswap.w.aq a5, a5, (s1)
  while(__sync_lock_test_and_set(&lk->locked, 1) != 0)
    ;

  // Tell the C compiler and the processor to not move loads or stores
  // past this point, to ensure that the critical section's memory
  // references happen strictly after the lock is acquired.
  // On RISC-V, this emits a fence instruction.
  __sync_synchronize();

  // Record info about lock acquisition for holding() and debugging.
  lk->cpu = mycpu();
}

// Release the lock.
void
release(struct spinlock *lk)
{
  if(!holding(lk))
    panic("release");

  lk->cpu = 0;

  // Tell the C compiler and the CPU to not move loads or stores
  // past this point, to ensure that all the stores in the critical
  // section are visible to other CPUs before the lock is released,
  // and that loads in the critical section occur strictly before
  // the lock is released.
  // On RISC-V, this emits a fence instruction.
  __sync_synchronize();

  // Release the lock, equivalent to lk->locked = 0.
  // This code doesn't use a C assignment, since the C standard
  // implies that an assignment might be implemented with
  // multiple store instructions.
  // On RISC-V, sync_lock_release turns into an atomic swap:
  //   s1 = &lk->locked
  //   amoswap.w zero, zero, (s1)
  __sync_lock_release(&lk->locked);

  pop_off();
}

// Check whether this cpu is holding the lock.
// Interrupts must be off.
int
holding(struct spinlock *lk)
{
  int r;
  r = (lk->locked && lk->cpu == mycpu());
  return r;
}

fileread(struct file *f, uint64 addr, int n)
{
  int r = 0;

  if(f->readable == 0)
    return -1;

  switch (f->type) {
    case FD_PIPE:
        r = piperead(f->pipe, addr, n);
        break;
    case FD_DEVICE:
        if (f->major == DEV_NULL)
          return 0;
        if (f->major == DEV_RTC)
          return 0;
        if (f->major == DEV_ZERO) {
          char zeros[128];
          memset(zeros, 0, sizeof(zeros));
          int total = 0;
          while (total < n) {
            int chunk = n - total;
            if (chunk > (int)sizeof(zeros)) chunk = (int)sizeof(zeros);
            if (copyout2(addr + total, zeros, chunk) < 0)
              return -1;
            total += chunk;
          }
          return total;
        }
        if(f->major < 0 || f->major >= NDEV || !devsw[f->major].read)
          return -1;
        r = devsw[f->major].read(1, addr, n);
        break;
    case FD_ENTRY:
        elock(f->ep);
          if((r = eread(f->ep, 1, addr, f->off, n)) > 0)
            f->off += r;
        eunlock(f->ep);
        break;
    case FD_EXT4: {
        char kbuf[512];
        ext4_acquire();
        ext4_file ef;
        int err = ext4_fopen(&ef, f->ext4path, "rb");
        if (err != EOK) { ext4_release(); return -1; }
        ext4_fseek(&ef, f->off, 0); // SEEK_SET
        int total = 0;
        while (total < n) {
            int chunk = n - total;
            if (chunk > (int)sizeof(kbuf)) chunk = (int)sizeof(kbuf);
            size_t got = 0;
            ext4_fread(&ef, kbuf, chunk, &got);
            if ((int)got <= 0) break;
            if (copyout2(addr + total, kbuf, got) < 0) {
                ext4_fclose(&ef);
                ext4_release();
                return -1;
            }
            total += got;
            if ((int)got < chunk) break;
        }
        ext4_fclose(&ef);
        ext4_release();
        f->off += total;
        r = total;
        break;
    }
    case FD_MEM: {
        void *oldroot = 0;
        uint oldsize = 0;
        if (f->mem_ref) {
          oldroot = f->mem;
          oldsize = f->mem_size;
          f->mem = f->mem_ref->root;
          f->mem_size = f->mem_ref->size;
        }
        int total = 0;
        while(total < n && f->off < f->mem_size) {
          uint pageno = f->off / PGSIZE;
          uint pageoff = f->off % PGSIZE;
          int chunk = PGSIZE - pageoff;
          if(chunk > n - total)
            chunk = n - total;
          if(chunk > (int)(f->mem_size - f->off))
            chunk = f->mem_size - f->off;
          char *page = memfile_page(f, pageno, 0);
          if(page == 0) {
            char zeros[128];
            memset(zeros, 0, sizeof(zeros));
            int done = 0;
            while(done < chunk) {
              int z = chunk - done;
              if(z > (int)sizeof(zeros)) z = sizeof(zeros);
              if(copyout2(addr + total + done, zeros, z) < 0)
                return -1;
              done += z;
            }
          } else if(copyout2(addr + total, page + pageoff, chunk) < 0) {
            return -1;
          }
          f->off += chunk;
          total += chunk;
        }
        if (f->mem_ref) {
          f->mem_ref->root = f->mem;
          f->mem_ref->size = f->mem_size;
          f->mem = oldroot;
          f->mem_size = oldsize;
        }
        r = total;
        break;
    }
    default:
      return -1;
  }

  return r;
}

// Write to file f.
// addr is a user virtual address.
int
filewrite(struct file *f, uint64 addr, int n)
{
  int ret = 0;

  if(f->writable == 0)
    return -1;

  if(f->type == FD_PIPE){
    ret = pipewrite(f->pipe, addr, n);
  } else if(f->type == FD_DEVICE){
    if (f->major == DEV_NULL || f->major == DEV_ZERO || f->major == DEV_RTC)
      return n;
    if(f->major < 0 || f->major >= NDEV || !devsw[f->major].write)
      return -1;
    ret = devsw[f->major].write(1, addr, n);
  } else if(f->type == FD_ENTRY){
    elock(f->ep);
    if (ewrite(f->ep, 1, addr, f->off, n) == n) {
      ret = n;
      f->off += n;
    } else {
      ret = -1;
    }
    eunlock(f->ep);
  } else if(f->type == FD_EXT4){
    char kbuf[512];
    ext4_acquire();
    ext4_file ef;
    int err = ext4_fopen2(&ef, f->ext4path, O_RDWR);
    if (err != EOK) { ext4_release(); return -1; }
    if (f->append)
      f->off = ext4_fsize(&ef);
    ext4_fseek(&ef, f->off, 0); // SEEK_SET
    int total = 0;
    while (total < n) {
      int chunk = n - total;
      if (chunk > (int)sizeof(kbuf)) chunk = (int)sizeof(kbuf);
      if (copyin2(kbuf, addr + total, chunk) < 0) {
        ext4_fclose(&ef);
        ext4_release();
        return -1;
      }
      size_t wcnt = 0;
      ext4_fwrite(&ef, kbuf, chunk, &wcnt);
      if ((int)wcnt <= 0) break;
      total += wcnt;
      if ((int)wcnt < chunk) break;
    }
    ext4_fclose(&ef);
    ext4_release();
    f->off += total;
    ret = total;
  } else if(f->type == FD_MEM){
    void *oldroot = 0;
    uint oldsize = 0;
    if (f->mem_ref) {
      oldroot = f->mem;
      oldsize = f->mem_size;
      f->mem = f->mem_ref->root;
      f->mem_size = f->mem_ref->size;
    }
    if (f->append)
      f->off = f->mem_size;
    int total = 0;
    while(total < n) {
      uint pageno = f->off / PGSIZE;
      uint pageoff = f->off % PGSIZE;
      int chunk = PGSIZE - pageoff;
      if(chunk > n - total)
        chunk = n - total;
      char *page = memfile_page(f, pageno, 1);
      if(page == 0)
        break;
      struct proc *p = myproc();
      if(copyin(p->pagetable, page + pageoff, addr + total, chunk) < 0) {
        return -1;
      }
      f->off += chunk;
      total += chunk;
      if(f->off > f->mem_size)
        f->mem_size = f->off;
    }
    if (f->mem_ref) {
      f->mem_ref->root = f->mem;
      f->mem_ref->size = f->mem_size;
      f->mem = oldroot;
      f->mem_size = oldsize;
    }
    ret = total;
  } else {
    return -1;
  }

  return ret;
}

