static int
ltp_find_busybox(const struct abi_info *abi, char *out, int cap)
{
    if (abi) {
        join_path(out, cap, abi->root, "busybox");
        if (ext4_supported_exec(out))
            return 0;
    }

    join_path(out, cap, "/musl/", "busybox");
    if (ext4_supported_exec(out))
        return 0;
    join_path(out, cap, "/glibc/", "busybox");
    if (ext4_supported_exec(out))
        return 0;
    join_path(out, cap, "/", "busybox");
    if (ext4_supported_exec(out))
        return 0;
    return -1;
}

static int
run_ltp_command_for_layout(const struct abi_info *abi,
                           const char *ltproot,
                           const char *bin_dir,
                           const char *tag,
                           const char *cmd,
                           char *const cmd_args[],
                           int cmd_argc)
{
    char exe[160];
    char busybox[128];
    char pathenv[256];
    char ldpathenv[192];
    char dataroot_env[160];
    char ltproot_env[128];
    char *envp[16];
    char *argv[LTP_MAX_ARGC];
    char arg_storage[LTP_MAX_ARGC][LTP_MAX_ARG_LEN];
    const char *run_path;
    const char *cwd = bin_dir;
    struct file *out = 0;
    int status = -1;
    int argc = 0;
    int script = 0;

    if (cmd_argc > LTP_MAX_ARGC - 4)
        cmd_argc = LTP_MAX_ARGC - 4;

    join_path(exe, sizeof(exe), bin_dir, cmd);
    if (ext4_supported_exec(exe)) {
        run_path = exe;
        argv[argc++] = exe;
    } else if (ext4_file_exists(exe) && has_suffix(cmd, ".sh") &&
               ltp_find_busybox(abi, busybox, sizeof(busybox)) == 0) {
        run_path = busybox;
        argv[argc++] = busybox;
        argv[argc++] = (char *)"sh";
        argv[argc++] = exe;
        script = 1;
    } else {
        return 0;
    }

    for (int i = 0; i < cmd_argc && argc < LTP_MAX_ARGC - 1; i++) {
        if (ltp_expand_arg(cmd_args[i], arg_storage[i],
                           sizeof(arg_storage[i]), ltproot) < 0)
            return 0;
        argv[argc++] = arg_storage[i];
    }
    argv[argc] = 0;

    ltp_build_env(abi, ltproot, bin_dir, pathenv, ldpathenv,
                  dataroot_env, ltproot_env, envp);
    clean_ltp_temporary_files();

    out = filealloc();
    if (!out)
        return -1;
    out->type = FD_MEM;
    out->readable = 1;
    out->writable = 1;
    out->mode = 0600;

    printf("RUN LTP CASE %s\n", tag);
    int pid = kernel_spawn_argv_capture(run_path, "ltp", cwd, argv, envp, out);
    if (pid < 0) {
        printf("FAIL LTP CASE %s : 127\n", tag);
        fileclose(out);
        return 0;
    }

    int timed_out = 0;
    uint64 deadline = r_time() + (script ? LTP_TIMEOUT_CYCLES * 3 :
                                  LTP_TIMEOUT_CYCLES);
    watchdog_pid = pid;
    watchdog_deadline = deadline;
    for (;;) {
        int wpid = wait_kernel(&status, pid, 1);
        if (wpid == pid)
            break;
        if (wpid < 0) {
            status = -1;
            break;
        }
        if (r_time() >= deadline) {
            timed_out = 1;
            kill(pid);
            wait_after_kill(pid, &status);
            break;
        }
        yield();
    }
    if (watchdog_pid == 0)
        timed_out = 1;
    watchdog_pid = 0;
    reap_zombies();

    if (timed_out) {
        printf("FAIL LTP CASE %s : 124\n", tag);
        fileclose(out);
        return 0;
    }

    if (status < 0)
        status = 1;
    else
        status = (status >> 8) & 0xff;

    if ((status == 0 || memfile_contains_token(out, "TPASS")) &&
        ltp_output_is_clean(out)) {
        if (replay_memfile_output(out) < 0) {
            fileclose(out);
            return -1;
        }
        printf("FAIL LTP CASE %s : 0\n", tag);
        fileclose(out);
        return 1;
    }

    replay_memfile_output(out);
    printf("FAIL LTP CASE %s : %d\n", tag, status == 0 ? 1 : status);
    fileclose(out);
    return 0;
}

static int
run_ltp_case_for_layout(const struct abi_info *abi,
                        const char *ltproot,
                        const char *bin_dir,
                        const char *name)
{
    char *args[1] = { 0 };

    return run_ltp_command_for_layout(abi, ltproot, bin_dir, name, name,
                                      args, 0);
}

static int
ltp_entry_name_is_usable(const char *name)
{
    if (name[0] == 0 || name[0] == '.')
        return 0;
    if (strcmp(name, "Makefile") == 0)
        return 0;
    return 1;
}

static int
ltp_collect_dir_names(const char *dir, int max_entries)
{
    ext4_dir d;
    int n = 0;

    if (max_entries > LTP_MAX_DIR_ENTRIES)
        max_entries = LTP_MAX_DIR_ENTRIES;

    ext4_acquire();
    int r = ext4_dir_open(&d, dir);
    if (r != EOK) {
        ext4_release();
        return -1;
    }

    const ext4_direntry *de;
    while ((de = ext4_dir_entry_next(&d)) != 0 && n < max_entries) {
        const char *name = (const char *)de->name;
        if (!ltp_entry_name_is_usable(name))
            continue;
        safestrcpy(ltp_dir_names[n], name, sizeof(ltp_dir_names[n]));
        n++;
    }
    ext4_dir_close(&d);
    ext4_release();
    return n;
}

static int
ltp_runtest_priority(const char *name)
{
    if (strcmp(name, "syscalls") == 0) return 0;
    if (strcmp(name, "syscalls-ipc") == 0) return 1;
    if (strcmp(name, "ipc") == 0) return 2;
    if (strcmp(name, "fs") == 0) return 3;
    if (strcmp(name, "fs_perms_simple") == 0) return 4;
    if (strcmp(name, "fs_readonly") == 0) return 5;
    if (strcmp(name, "mm") == 0) return 6;
    if (strcmp(name, "sched") == 0) return 7;
    if (strcmp(name, "pty") == 0) return 8;
    if (strcmp(name, "commands") == 0) return 9;
    if (strcmp(name, "capability") == 0) return 10;
    if (strcmp(name, "cve") == 0) return 11;
    if (strcmp(name, "smoketest") == 0) return 12;
    return 100;
}

static void
ltp_sort_runtest_names(int n)
{
    for (int i = 0; i < n; i++) {
        int best = i;
        for (int j = i + 1; j < n; j++) {
            int pj = ltp_runtest_priority(ltp_dir_names[j]);
            int pb = ltp_runtest_priority(ltp_dir_names[best]);
            if (pj < pb ||
                (pj == pb && strcmp(ltp_dir_names[j], ltp_dir_names[best]) < 0))
                best = j;
        }
        if (best != i) {
            char tmp[64];
            safestrcpy(tmp, ltp_dir_names[i], sizeof(tmp));
            safestrcpy(ltp_dir_names[i], ltp_dir_names[best],
                       sizeof(ltp_dir_names[i]));
            safestrcpy(ltp_dir_names[best], tmp, sizeof(ltp_dir_names[best]));
        }
    }
}

static int
run_ltp_runtest_line(const struct abi_info *abi,
                     const char *ltproot,
                     const char *bin_dir,
                     char *line)
{
    char *words[LTP_MAX_ARGC];
    int argc;

    while (*line == ' ' || *line == '\t')
        line++;
    if (*line == 0 || *line == '#')
