static int
run_ltp_for_abi(const struct abi_info *abi, int full)
{
    char group[32];
    char ltproot[96];
    char bin_dir[128];
    int pos = 0;

    group[0] = 0;
    if (append_text(group, sizeof(group), &pos, "ltp-") < 0 ||
        append_text(group, sizeof(group), &pos, abi->name) < 0)
        return -1;

    join_path(ltproot, sizeof(ltproot), abi->root, "ltp");
    join_path(bin_dir, sizeof(bin_dir), ltproot, "testcases/bin");
    if (full)
        return run_ltp_full_for_layout(abi, group, ltproot, bin_dir);
    return run_ltp_smoke_for_layout(abi, group, ltproot, bin_dir);
}

static int
run_ltp_top_level(int full)
{
    if (full)
        return run_ltp_full_for_layout(0, "ltp", "/ltp", "/ltp/testcases/bin");
    return run_ltp_smoke_for_layout(0, "ltp", "/ltp", "/ltp/testcases/bin");
}

static void
run_ltp_groups_mode(int full)
{
    int any_layout = 0;

    for (int j = 0; j < NUM_ABIS; j++) {
        int r = run_ltp_for_abi(&abis[j], full);
        if (r < 0) {
            emit_empty_group("ltp", &abis[j]);
        } else {
            any_layout = 1;
        }
    }

    if (!any_layout)
        run_ltp_top_level(full);
}

static void __attribute__((unused))
run_ltp_groups(void)
{
    run_ltp_groups_mode(0);
}

static void __attribute__((unused))
run_ltp_full_groups(void)
{
    run_ltp_groups_mode(1);
}

void
runtests(void)
{
    // Arm the global deadline immediately so even a stuck mount triggers
    // a forced shutdown rather than hanging the eval forever.
    global_deadline = r_time() + GLOBAL_BUDGET_CYCLES;

    printf("\n[runtests] mounting EXT4 on vda...\n");
    int r = ext4_glue_init();
    if (r != 0) {
        printf("[runtests] mount failed (%d); emitting empty groups.\n", r);
        emit_empty_all_groups();
        sbi_shutdown();
        for (;;) ;
    }

    printf("[runtests] mount OK, scanning filesystem\n");
    int found = 0;
    found += scan_dir("/");
    found += scan_dir("/musl/");
    found += scan_dir("/glibc/");
    printf("[runtests] total %d *_testcode.sh located\n", found);

    // Set up console fds on initproc so wait() works
    install_console_fds();
    prepare_busybox_workspace();

#ifdef BENCH_ONLY
    run_iozone_groups();
    run_lmbench_groups();
    printf("\n[runtests] bench-only run done, shutting down.\n");
    sbi_shutdown();
    for (;;) ;
#endif

#ifdef LTP_ONLY
#ifdef LTP_FULL_ONLY
    run_ltp_full_groups();
#else
    run_ltp_groups();
#endif
    printf("\n[runtests] ltp-only run done, shutting down.\n");
    sbi_shutdown();
    for (;;) ;
#endif

    run_libctest_groups();

#ifdef LIBCTEST_ONLY
    printf("\n[runtests] libctest-only run done, shutting down.\n");
    sbi_shutdown();
    for (;;) ;
#endif

    // Detect which ABI prefixes have basic tests.
    int abi_present[NUM_ABIS] = {0};
    for (int j = 0; j < NUM_ABIS; j++) {
        char probe[128];
        strncpy(probe, abis[j].basic_prefix, sizeof(probe));
        int plen = strlen(probe);
        strncpy(probe + plen, "write", sizeof(probe) - plen);
        abi_present[j] = ext4_supported_exec(probe);
        printf("[runtests] %s basic %s\n", abis[j].name,
               abi_present[j] ? "PRESENT" : "absent");
        if (abi_present[j])
            prepare_basic_workspace(&abis[j]);
    }

    // Run every ABI that is present on the image. A per-test watchdog prevents
    // one unsupported binary from blocking the whole evaluation.
    for (int j = 0; j < NUM_ABIS; j++) {
        int run_abi = abi_present[j];
        if (run_abi) {
            run_basic_for_abi(&abis[j]);
        } else {
            printf("#### OS COMP TEST GROUP START basic-%s ####\n", abis[j].name);
            printf("#### OS COMP TEST GROUP END basic-%s ####\n", abis[j].name);
        }
    }

    run_busybox_groups();
    run_lua_groups();
    run_libcbench_groups();

    run_lmbench_groups();

    // Empty frames for the remaining groups, per ABI, so eval sees well-formed
    // output for every scoreboard cell.
    emit_empty_other_groups();

    // Keep LTP in the normal late position; known earlier stalls are handled
    // in their own suites so the default ordering stays close to the judge run.
    run_ltp_full_groups();  // Use full/priority mode instead of smoke

    printf("\n[runtests] done, shutting down.\n");
    sbi_shutdown();
    for (;;) ;
}

